+// =============================================================================
+// Q5_K MATVEC KERNEL (for attention O projection in Q5_K quantized models)
+// =============================================================================
+// Q5_K Block Structure: 256 values in 176 bytes (5.5 bpw)
+// GGML Q5_K layout: [d (f16)][dmin (f16)][scales[12]][qh[32]][qs[128]]
+struct block_q5_K {
+    half d;           // Super-block scale (2 bytes)
+    half dmin;        // Super-block min (2 bytes)
+    uchar scales[12]; // 6-bit scales packed (12 bytes, same as Q4_K)
+    uchar qh[32];     // High bits: 1 bit per value (32 bytes = 256 bits)
+    uchar qs[128];    // Low 4 bits: 2 values per byte (128 bytes)
+};                    // Total: 2+2+12+32+128 = 176 bytes
+
+/// Pure Q5_K matvec for attention O projection
+/// Each threadgroup (32 threads) computes one output row
+kernel void moe_matvec_q5k_simd(
+    device const uchar *weights_q5k [[buffer(0)]],    // Q5_K weights [m, n]
+    device const float *input [[buffer(1)]],          // Input vector [n]
+    device float *output [[buffer(2)]],               // Output vector [m]
+    constant uint &nb00 [[buffer(3)]],                // Row stride in bytes
+    constant uint &ne00 [[buffer(4)]],                // Row size in elements (must be multiple of 256)
+    uint3 tgpig [[threadgroup_position_in_grid]],
+    uint tiisg [[thread_index_in_simdgroup]]
+) {
+    const int row_idx = tgpig.x;
+    const int row_offset = row_idx * nb00;
+
+    device const block_q5_K *current_block = (device const block_q5_K *)(weights_q5k + row_offset);
+
+    float sum = 0.0f;
+    const int num_blocks = ne00 / 256;
+
+    for (int block_idx = tiisg; block_idx < num_blocks; block_idx += 32) {
+        device const block_q5_K *b = current_block + block_idx;
+        const float d = (float)b->d;
+        const float dmin = (float)b->dmin;
+        const int input_offset = block_idx * 256;
+
+        float block_sum = 0.0f;
+
+        // Process 4 chunks of 64 values each (matching Q4_K structure)
+        // Scales are packed same as Q4_K
+        for (int chunk = 0; chunk < 4; chunk++) {
+            const int is = chunk * 2;  // scale index
+            const int qs_offset = chunk * 32;  // 32 bytes per chunk in qs
+            const int qh_offset = chunk * 8;   // 8 bytes per chunk in qh
+            const int x_offset = input_offset + chunk * 64;
+
+            // Get scale/min for first 32 values (low nibbles)
+            float d1, m1;
+            if (is < 4) {
+                d1 = d * (float)(b->scales[is] & 63);
+                m1 = dmin * (float)(b->scales[is + 4] & 63);
+            } else {
+                d1 = d * (float)((b->scales[is + 4] & 0x0F) | ((b->scales[is - 4] >> 6) << 4));
+                m1 = dmin * (float)((b->scales[is + 4] >> 4) | ((b->scales[is] >> 6) << 4));
+            }
+
+            // Get scale/min for next 32 values (high nibbles)
+            float d2, m2;
+            if (is + 1 < 4) {
+                d2 = d * (float)(b->scales[is + 1] & 63);
+                m2 = dmin * (float)(b->scales[is + 1 + 4] & 63);
+            } else {
+                d2 = d * (float)((b->scales[is + 1 + 4] & 0x0F) | ((b->scales[is + 1 - 4] >> 6) << 4));
+                m2 = dmin * (float)((b->scales[is + 1 + 4] >> 4) | ((b->scales[is + 1] >> 6) << 4));
+            }
+
+            // Process 32 low nibbles (indices 0-31 within this chunk)
+            // The 5-bit value = 4-bit low + 16 if high bit set
+            for (int l = 0; l < 32; l++) {
+                uchar q4 = b->qs[qs_offset + l] & 0xF;
+                // qh is packed: bit (l % 8) of byte (qh_offset + l/8)
+                uchar hbyte = b->qh[qh_offset + l/8];
+                uchar hbit = (hbyte >> (l % 8)) & 1;
+                float q5 = (float)q4 + (hbit ? 16.0f : 0.0f);
+                float x = input[x_offset + l];
+                block_sum += x * (d1 * q5 - m1);
+            }
+
+            // Process 32 high nibbles (indices 32-63 within this chunk)
+            for (int l = 0; l < 32; l++) {
+                uchar q4 = b->qs[qs_offset + l] >> 4;
+                // For high nibbles, use second half of qh bytes (offset by 4)
+                uchar hbyte = b->qh[qh_offset + 4 + l/8];
+                uchar hbit = (hbyte >> (l % 8)) & 1;
+                float q5 = (float)q4 + (hbit ? 16.0f : 0.0f);
+                float x = input[x_offset + 32 + l];
+                block_sum += x * (d2 * q5 - m2);
+            }
+        }
+
+        sum += block_sum;
+    }
+
+    sum = simd_sum(sum);
+
+    if (tiisg == 0) {
+        output[row_idx] = sum;
+    }
+}
