+/// Q3_K Down projection kernel WITH CSR sparse corrections
+/// Combines Q3_K matmul + CSR delta corrections for hybrid inference
+/// CSR corrections: delta = Q4K_FP32 - Q3K_FP32 (fixes quantization errors)
+kernel void moe_down_proj_q3k_sparse(
+    device const uchar *down_q3k [[buffer(0)]],       // [n_embd, n_ff] Q3_K
+    device const float *activated [[buffer(1)]],      // [batch_size, n_ff]
+    device float *output [[buffer(2)]],               // [batch_size, n_embd]
+    constant uint &batch_size [[buffer(3)]],
+    constant uint &n_embd [[buffer(4)]],
+    constant uint &n_ff [[buffer(5)]],
+    constant uint &batch_offset [[buffer(6)]],
+    constant uint *token_indices [[buffer(7)]],
+    // CSR sparse correction buffers (delta = Q4K - Q3K)
+    device const uint *csr_row_ptr [[buffer(8)]],     // [n_embd + 1]
+    device const ushort *csr_col_idx [[buffer(9)]],   // [nnz]
+    device const half *csr_values [[buffer(10)]],     // [nnz]
+    uint3 tgpig [[threadgroup_position_in_grid]],
+    uint tiisg [[thread_index_in_simdgroup]]
+) {
+    // X-axis dispatch: row_idx from .x (matches Q2K pattern)
+    const int row_idx = tgpig.x;
+    const int local_idx = tgpig.y;
+
+    if (local_idx >= batch_size || row_idx >= n_embd) return;
+
+    const int actual_token_idx = (token_indices != nullptr) ? token_indices[local_idx] : (local_idx + batch_offset);
+    const int batch_idx = actual_token_idx;
+
+    // Q3_K: 110 bytes per 256 values
+    const int blocks_per_row = (n_ff + 255) / 256;
+    const int row_stride_bytes = blocks_per_row * 110;
+
+    device const block_q3_K *row_blocks = (device const block_q3_K *)(down_q3k + row_idx * row_stride_bytes);
+
+    float sum = 0.0f;
+    const int batch_activated_offset = batch_idx * n_ff;
+
+    // === PHASE 1: Q3_K base matmul ===
+    // Process blocks in parallel across SIMD lanes
+    for (int block_idx = tiisg; block_idx < blocks_per_row; block_idx += 32) {
+        device const block_q3_K *b = row_blocks + block_idx;
+
+        const float d = (float)b->d;
+        const int base_offset = batch_activated_offset + block_idx * 256;
+
+        // Decode scales from packed 6-bit format
+        uchar sc[8];
+        sc[0] = (b->scales[0] & 0x3F);
+        sc[1] = ((b->scales[0] >> 6) | ((b->scales[1] & 0x0F) << 2));
+        sc[2] = ((b->scales[1] >> 4) | ((b->scales[2] & 0x03) << 4));
+        sc[3] = (b->scales[2] >> 2);
+        sc[4] = (b->scales[3] & 0x3F);
+        sc[5] = ((b->scales[3] >> 6) | ((b->scales[4] & 0x0F) << 2));
+        sc[6] = ((b->scales[4] >> 4) | ((b->scales[5] & 0x03) << 4));
+        sc[7] = (b->scales[5] >> 2);
+
+        // Process all 256 values in this block
+        for (int i = 0; i < 256; i++) {
+            const int abs_idx = block_idx * 256 + i;
+            if (abs_idx >= n_ff) break;
+
+            // Extract low 2 bits from qs (4 values per byte)
+            uint qs_byte = i / 4;
+            uint qs_shift = (i % 4) * 2;
+            uint q_low = (b->qs[qs_byte] >> qs_shift) & 0x3;
+
+            // Extract high bit from hmask (8 values per byte)
+            uint hmask_byte = i / 8;
+            uint hmask_bit = i % 8;
+            uint q_high = (b->hmask[hmask_byte] >> hmask_bit) & 0x1;
+
+            // Combine to 3-bit value (0-7)
+            int q3 = (int)(q_low | (q_high << 2));
+
+            // Get scale for this group (8 groups of 32)
+            uint group = i / 32;
+            float scale = (float)sc[group];
+
+            // Q3_K dequantization (sparse): val = d * scale * (q - 4)
+            float w = d * scale * (float)(q3 - 4);
+
+            sum += activated[base_offset + i] * w;
+        }
+    }
+
+    // SIMD reduction
+    sum = simd_sum(sum);
+
+    // === PHASE 2: Sparse outlier correction ===
+    // Only thread 0 handles sparse correction and output
+    if (tiisg == 0) {
+        // Add CSR sparse corrections if buffers are provided
+        // CSR format: for row row_idx, non-zeros are at indices [row_ptr[row_idx], row_ptr[row_idx+1])
+        if (csr_row_ptr != nullptr && csr_col_idx != nullptr && csr_values != nullptr) {
+            uint start = csr_row_ptr[row_idx];
+            uint end = csr_row_ptr[row_idx + 1];
+            for (uint i = start; i < end; i++) {
+                ushort col = csr_col_idx[i];
+                float val = (float)csr_values[i];
+                // delta correction: activated[col] * (Q4K - Q3K)
+                sum += val * activated[batch_activated_offset + col];
+            }
+        }
+
+        const int output_idx = batch_idx * n_embd + row_idx;
+        output[output_idx] = sum;
+    }
+}

